//! Terminal escape sequence handler — struct definition and routing.
//!
//! The `TerminalHandler` struct holds mutable borrows of all terminal state
//! needed during VT sequence processing. Its methods are split across
//! concern-based submodules (#2157):
//!
//! ## Concern layers
//!
//! - **Parser actions** (`handler_actions.rs`): `ActionSink` trait impl —
//!   receives parsed events and dispatches to typed handler methods.
//!   Depends on: `parser`, `charset`.
//!
//! - **State transitions** (`handler_state.rs`): grid/mode mutations —
//!   cursor movement, erase, scroll, insert/delete, DECSTR, DSR/DA, etc.
//!   Depends on: `grid`, `bidi`, `config`, `vt_level`.
//!
//! - **Protocol dispatch** (`handler_csi.rs`, `handler_esc.rs`,
//!   `handler_dcs.rs`): intermediary routing from parser actions to
//!   state-transition or side-effect methods.
//!
//! - **Side-effects** (inline in protocol handlers): callbacks and external
//!   service activation (bell, buffer switch).

use crate::grid::{Grid, StyleId};

use super::{
    BufferActivationCallback, CurrentStyle, DcsState, MAX_RESPONSE_BUFFER_SIZE, TerminalModes,
    TransientState, Vt52CursorState, WindowCallback,
};
use aterm_types::KittyKeyboardState;
use aterm_types::charset::CharacterSetState;

// Submodules routed via #[path] since they are siblings of handler.rs.
// Concern layers (#2157):
//   - Parser actions: handler_actions (ActionSink trait impl)
//   - Protocol dispatch: handler_csi, handler_dcs, handler_esc
//   - Character write path: handler_write
#[path = "handler_actions.rs"]
mod handler_actions;
#[path = "handler_csi.rs"]
mod handler_csi;
#[path = "handler_dcs.rs"]
mod handler_dcs;
#[path = "handler_esc.rs"]
mod handler_esc;
#[path = "handler_write.rs"]
mod handler_write;
// Re-exported so the render-cell extraction (a sibling of `handler`) can flag
// emoji-presentation cells with the SAME predicate the writer uses for VS16.
pub(crate) use handler_write::is_vs16_emoji_capable;

/// Single-source-of-truth mapping from `TerminalHandler` fields to `Terminal`
/// borrow paths (#3560).
///
/// Each entry: `handler_field: Type => terminal.borrow.path`
///
/// Generates:
/// - `TerminalHandler<'a>` struct (all fields as `pub(super) &'a mut`)
/// - `Terminal::split_for_process()` returning `(&mut Parser, TerminalHandler<'_>)`
///
/// Adding or removing a handler field is a single-line edit. The struct
/// definition and construction cannot go out of sync.
///
/// ## Grouped state fields
///
/// Several Terminal sub-structs are passed as whole borrows rather than
/// splitting into individual fields:
///
/// - `transient` — response buffer, hyperlink, underline color, SGR stack,
///   VT52 state, sync start, last graphic char
macro_rules! define_terminal_handler {
    (
        $(
            $(#[$meta:meta])*
            $field:ident : $ty:ty => $($path:ident).+
        ),*
        $(,)?
    ) => {
        /// Internal handler struct for parser callbacks.
        ///
        /// Holds mutable borrows of all terminal state needed during VT
        /// processing. Generated by [`define_terminal_handler!`] so that the
        /// struct definition and `split_for_process()` construction stay in
        /// sync automatically (#3560).
        pub(super) struct TerminalHandler<'a> {
            $(
                $(#[$meta])*
                pub(super) $field: &'a mut $ty,
            )*
        }

        impl super::Terminal {
            /// Split `Terminal` into parser + handler borrows for VT processing.
            ///
            /// Returns disjoint mutable borrows: the parser (for `advance_fast`)
            /// and all handler-accessible fields. Generated by
            /// [`define_terminal_handler!`] (#3560).
            pub(super) fn split_for_process(
                &mut self,
            ) -> (&mut crate::parser::Parser, TerminalHandler<'_>) {
                (
                    &mut self.parser,
                    TerminalHandler {
                        $(
                            $(#[$meta])*
                            $field: &mut self.$($path).+,
                        )*
                    },
                )
            }
        }
    };
}

// --- Field mapping: handler field => Terminal borrow path ---
//
// To forward a new Terminal field to the handler, add one line here.
// To stop forwarding, delete the line. No other edits required.
define_terminal_handler! {
    // Core state (grid, modes, style)
    grid: Grid => grid,
    modes: TerminalModes => modes,
    style: CurrentStyle => style,
    current_style_id: StyleId => current_style_id,
    charset: CharacterSetState => charset,
    alt_grid: Option<Grid> => alt_grid,
    cursor_save: super::CursorSaveState => cursor_save,

    // Protocol state
    dcs: DcsState => dcs,
    shell: super::ShellIntegrationState => shell,
    marks_state: super::MarksState => marks_state,
    semantic: super::SemanticState => semantic,
    color: super::ColorState => color,
    #[cfg(feature = "sixel")]
    sixel: super::SixelState => sixel,
    kitty_keyboard: KittyKeyboardState => kitty_keyboard,
    xterm_keyboard: super::XtermKeyboardState => xterm_keyboard,

    // Transient I/O state (grouped)
    transient: TransientState => transient,
    // OSC / escape-sequence policy engine (#7994, #7995, #7996). Hot-swappable
    // at runtime via `Terminal::apply_policy_engine`. `None` when no policy is
    // installed — in that case `send_response` and the OSC palette handlers fall
    // back to the legacy `TransientState::response_rate_limiter` + inline
    // per-sequence counter, and capability handlers read via
    // `policy_bridge::engine_decision(self.policy_engine.as_deref(), ...)`
    // falling back to `TerminalModes::allow_*` / per-capability `authorized`
    // state. See `response_rate_limiter.rs` and `policy_bridge.rs` module docs,
    // and designs/2026-04-19-osc-policy-engine.md §6.3 for the Release N
    // deprecation-window semantics.
    policy_engine: Option<aterm_policy::engine::PolicyEngine> => policy_engine,
    current_working_directory: Option<String> => current_working_directory,
    // Platform flag: secure keyboard entry (reset by RIS, #7336)
    secure_keyboard_entry: bool => secure_keyboard_entry,

    // Side-effect state (callbacks, external services)
    title: super::TitleState => title,
    bell_callback: Option<Box<dyn FnMut() + Send>> => bell_callback,
    last_bell_time: Option<std::time::Instant> => last_bell_time,
    cursor_style_callback: Option<Box<dyn FnMut(aterm_types::CursorStyle) + Send>> => cursor_style_callback,
    buffer_activation_callback: Option<BufferActivationCallback> => buffer_activation_callback,
    notifications: super::NotificationState => notifications,
    clipboard: super::ClipboardState => clipboard,
    iterm2: super::Iterm2State => iterm2,
    window_callback: Option<WindowCallback> => window_callback,
    text_sizing_callback: Option<super::callbacks::TextSizingCallback> => text_sizing_callback,
    taskbar_progress: Option<super::TaskbarProgress> => taskbar_progress,
    // Host-side OSC 52 clipboard authorization (CF-004, CF-005).
    // The only path to ClipboardWriteCapability / ClipboardQueryCapability
    // is through this field's `try_mint_*_capability` methods, which
    // require prior host-side authorization via
    // `Terminal::authorize_clipboard_access`. Handlers cannot construct
    // the zero-sized tokens directly (private `_seal: ()` fields) — so
    // the parser path cannot reach the clipboard callback without a
    // host-issued capability. See super::clipboard_auth.
    clipboard_auth: super::clipboard_auth::ClipboardAuth => clipboard_auth,
    // Host-side OSC 133 / OSC 633 shell-integration capability-nonce
    // authorization (#7937 F01-2, #7960). When
    // `modes.require_shell_integration_nonce` is set, the OSC 133/633
    // handlers call `shell_integration_auth.verify_nonce(params)` and
    // silently drop sequences whose `id=<hex>` does not match the
    // host-authorized nonce. The only path to authorize is through
    // `Terminal::authorize_shell_integration`. See
    // super::shell_integration_auth.
    shell_integration_auth: super::shell_integration_auth::ShellIntegrationAuth
        => shell_integration_auth,
    // Host-side OSC 8 hyperlink URI-acceptance authorization (CF-014).
    // The only path to `HyperlinkCapability` is through this field's
    // `try_mint_capability` method, which requires prior host-side
    // authorization via `Terminal::authorize_hyperlinks` (defaults to
    // authorized for backward-compat). Handlers cannot construct the
    // zero-sized token directly (private `_seal: ()` field) — so the
    // parser path cannot write `transient.current_hyperlink` without a
    // host-issued capability. See super::hyperlink_auth.
    hyperlink_auth: super::hyperlink_auth::HyperlinkAuth => hyperlink_auth,
    // Host-side raw DCS callback delivery authorization (CF-013).
    // The only path to `DcsEmitCapability` is through this field's
    // `try_mint_capability` method, which requires prior host-side
    // authorization via `Terminal::authorize_dcs` (defaults to
    // authorized for backward-compat). Handlers cannot construct the
    // zero-sized token directly (private `_seal: ()` field) — so the
    // parser path cannot reach `self.dcs.callback` without a host-
    // issued capability. See super::dcs_auth.
    dcs_auth: super::dcs_auth::DcsAuth => dcs_auth,
}

/// Narrow SGR-only borrow view extracted from `TerminalHandler` for style and
/// color mutations.
pub(super) struct SgrStyleHandler<'a> {
    pub(super) grid: &'a mut Grid,
    pub(super) style: &'a mut CurrentStyle,
    pub(super) current_style_id: &'a mut StyleId,
    pub(super) transient: &'a mut TransientState,
}

/// Narrow cursor/state borrow view extracted from `TerminalHandler` for grid
/// motion, cursor save/restore, and related mode updates.
pub(super) struct CursorStateHandler<'a> {
    pub(super) grid: &'a mut Grid,
    pub(super) style: &'a mut CurrentStyle,
    pub(super) modes: &'a mut TerminalModes,
    pub(super) charset: &'a mut CharacterSetState,
    pub(super) cursor_save: &'a mut super::CursorSaveState,
    pub(super) cursor_style_callback:
        &'a mut Option<Box<dyn FnMut(aterm_types::CursorStyle) + Send>>,
    /// Current underline color for DECSC/DECRC save/restore (#7295).
    pub(super) underline_color: &'a mut Option<u32>,
    /// Cached `has_transient_extras` flag for DECRC update (#7403).
    pub(super) has_transient_extras: &'a mut bool,
    /// Whether a hyperlink is currently set (read-only snapshot for extras recomputation).
    pub(super) has_hyperlink: bool,
}

// ---------------------------------------------------------------------------
// Narrow reborrow constructors used directly by the routing modules
// ---------------------------------------------------------------------------

impl TerminalHandler<'_> {
    pub(super) fn sgr_style(&mut self) -> SgrStyleHandler<'_> {
        SgrStyleHandler {
            grid: &mut *self.grid,
            style: &mut *self.style,
            current_style_id: &mut *self.current_style_id,
            transient: &mut *self.transient,
        }
    }

    pub(super) fn cursor_state(&mut self) -> CursorStateHandler<'_> {
        CursorStateHandler {
            grid: &mut *self.grid,
            style: &mut *self.style,
            modes: &mut *self.modes,
            charset: &mut *self.charset,
            cursor_save: &mut *self.cursor_save,
            cursor_style_callback: &mut *self.cursor_style_callback,
            underline_color: &mut self.transient.current_underline_color,
            has_transient_extras: &mut self.transient.has_transient_extras,
            has_hyperlink: self.transient.current_hyperlink.is_some(),
        }
    }

    /// Handle BEL (0x07): fire bell callback.
    ///
    /// Rate-limited to at most one callback per 100ms to prevent DoS via
    /// BEL flooding. A malicious program can emit millions of 0x07 bytes
    /// per second; without throttling, each one crosses the FFI boundary
    /// as a callback invocation.
    pub(super) fn handle_bell(&mut self) {
        const MIN_BELL_INTERVAL: std::time::Duration = std::time::Duration::from_millis(100);

        let now = std::time::Instant::now();
        if let Some(last) = *self.last_bell_time {
            if now.duration_since(last) < MIN_BELL_INTERVAL {
                return;
            }
        }
        *self.last_bell_time = Some(now);

        if let Some(callback) = self.bell_callback {
            callback();
        }
    }

    /// Invalidate all cached BiDi resolutions (no-op: the BiDi render cache
    /// lives behind the permanently compiled-out `aterm-bidi` integration;
    /// see `bidi_stubs.rs`).
    #[inline]
    #[allow(
        clippy::unused_self,
        reason = "no-op stub mirrors the &mut self signature of the real bidi method"
    )]
    pub(super) fn invalidate_bidi_all(&mut self) {}

    /// Perform a line feed (#7687).
    #[inline]
    pub(super) fn line_feed_with_kitty_adjust(&mut self, left_right_margin_mode: bool) {
        self.grid.line_feed_margined(left_right_margin_mode);
    }

    /// Write a response to the response buffer.
    ///
    /// Used for DSR/DA and other sequences that require a terminal response.
    ///
    /// Responses are gated by two independent limits:
    /// 1. [`MAX_RESPONSE_BUFFER_SIZE`] caps the *total buffered* response
    ///    bytes waiting for the host to drain.
    /// 2. The [`ResponseRateLimiter`][rl] caps the *rate* at which responses
    ///    can be generated, defending against DSR/DA amplification attacks
    ///    when the host drains the buffer in a tight loop (Part of #7874).
    ///
    /// Responses that fail either check are silently dropped — the same
    /// contract as the pre-#7874 buffer-full path, so handlers don't need
    /// to distinguish.
    ///
    /// [rl]: super::response_rate_limiter::ResponseRateLimiter
    ///
    /// # Capability gate (CF-003, #7878)
    ///
    /// The `_cap` parameter is a zero-sized
    /// [`ResponseCapability`][rc] that proves the caller is inside a
    /// parser-dispatched CSI/ESC/OSC/DCS frame — the only legitimate
    /// origin for a PTY response. A handler that calls `send_response`
    /// outside such a frame cannot construct the token and fails to
    /// compile. This complements the runtime rate limiter and buffer
    /// cap with a compile-time provenance check.
    ///
    /// [rc]: super::response_capability::ResponseCapability
    pub(super) fn send_response(
        &mut self,
        _cap: &super::response_capability::ResponseCapability,
        response: &[u8],
    ) {
        if !self.can_append_response_bytes(response.len()) {
            return;
        }
        // Rate-limit gate: the policy engine's `"response"` bucket is the
        // single source of truth when a policy is installed (#7995). If no
        // policy engine is present, fall back to the legacy in-transient
        // `ResponseRateLimiter` so hosts that haven't opted in see zero
        // behavioral change.
        let bytes = response.len() as u64;
        let clock = aterm_policy::limits::SystemClock;
        let permitted = if let Some(engine) = self.policy_engine.as_mut() {
            engine.rate_limit_try_consume("response", bytes, &clock)
        } else {
            let legacy_clock = super::response_rate_limiter::SystemTime;
            self.transient
                .response_rate_limiter
                .try_consume(response.len(), &legacy_clock)
        };
        if !permitted {
            return;
        }
        self.transient.response_buffer.extend_from_slice(response);
    }

    /// Returns whether appending `additional_len` would stay within the cap.
    fn can_append_response_bytes(&self, additional_len: usize) -> bool {
        self.transient
            .response_buffer
            .len()
            .saturating_add(additional_len)
            <= MAX_RESPONSE_BUFFER_SIZE
    }

    /// Filter DCS data for safe echoing in responses.
    ///
    /// Removes escape sequences and control characters to prevent
    /// DECRQSS injection attacks. When terminals echo query responses
    /// back to shells, embedded escape sequences could inject commands.
    ///
    /// Only keeps printable ASCII and space (0x20-0x7E).
    /// See: dgl.cx/2023/09/ansi-terminal-security
    pub(super) fn filter_dcs_data_for_response(data: &[u8]) -> Vec<u8> {
        data.iter()
            .copied()
            .filter(|&b| (0x20..=0x7E).contains(&b))
            .collect()
    }
}

